const body = $input.first().json.body || $input.first().json;
const lux = body.lux;
const lang = body.language || 'en';

let lightType, plants;

if (lux === undefined) {
  return [{ json: { mode: 'vision', lang, body } }];
}

if (lux < 500) {
  lightType = lang === 'es' ? 'Poca luz' : 'Low light';
  plants = ['Pothos', 'ZZ Plant', 'Snake Plant', 'Cast Iron Plant', 'Dracaena'];
} else if (lux < 2500) {
  lightType = lang === 'es' ? 'Luz media' : 'Medium light';
  plants = ['Monstera', 'Philodendron', 'Peace Lily', 'Chinese Evergreen', 'Dumb Cane'];
} else if (lux < 10000) {
  lightType = lang === 'es' ? 'Luz indirecta brillante' : 'Bright indirect light';
  plants = ['Fiddle Leaf Fig', 'Bird of Paradise', 'Rubber Plant', 'Alocasia', 'Calathea'];
} else {
  lightType = lang === 'es' ? 'Sol directo' : 'Full sun';
  plants = ['Cactus', 'Succulents', 'Herbs', 'Aloe Vera', 'Lavender'];
}

return [{ json: { lux, lightType, plants, lang } }];
